template.content:
# General lifecycle evolution event
{{modelName}}Evolved:
  description: "{{modelName}} lifecycle state changed"
  attributes:
    id: UUID required
    {{#each model.attributes}}
    {{#if (eq name "name")}}
    {{name}}: {{type}} optional
    {{/if}}
    {{/each}}
    fromState: String required
    toState: String required
    transitionName: String required
    reason: String optional
    triggeredBy: UUID required
    timestamp: DateTime required
    validationsPassed: Boolean required
    sideEffectsCompleted: Boolean required

{{#each model.lifecycle.transitions}}
# Specific transition events
{{../modelName}}{{name}}:
  description: "{{../modelName}} transitioned from {{from}} to {{to}}"
  attributes:
    id: UUID required
    {{#each ../../model.attributes}}
    {{#if (eq name "name")}}
    {{name}}: {{type}} optional
    {{/if}}
    {{/each}}
    fromState: String default={{from}}
    toState: String default={{to}}
    transitionName: String default={{name}}
    prerequisites: String optional
    triggeredBy: UUID required
    timestamp: DateTime required
    duration: Integer optional
    {{#if conditions}}
    conditionsMet: Object optional
    {{/if}}
{{/each}}
